// ── Validate & Sanitize Input ──
const body = $input.first().json.body;

const store_id = body.store_id;
const session_id = body.session_id;
const message = (body.message || '').trim().slice(0, 2000);
const conversation_id = body.conversation_id || null;
const conversation_history = body.conversation_history || [];

if (!store_id) throw new Error('Missing required field: store_id');
if (!message) throw new Error('Missing required field: message');

// Prompt injection defense
const injectionPatterns = [
  'ignore previous instructions',
  'ignore all instructions',
  'disregard your instructions',
  'system prompt',
  'you are now',
  'jailbreak',
  'DAN mode'
];

let safeMessage = message;
injectionPatterns.forEach(pattern => {
  safeMessage = safeMessage.replace(new RegExp(pattern, 'gi'), '[removed]');
});

return [{
  json: {
    store_id,
    session_id,
    message: safeMessage,
    conversation_id,
    conversation_history
  }
}];

// ── Build pgvector query with embedding ──
const embedding = $('Embed Query — OpenAI').item.json.data[0].embedding;
const store_id = $('Validate & Sanitize Input').item.json.store_id;
const aiConfig = $('Fetch AI Config').item.json;
const topK = aiConfig.top_k_retrieval || 6;
const threshold = aiConfig.similarity_threshold || 0.70;

// Format the embedding as a pgvector-compatible string
const embeddingStr = '[' + embedding.join(',') + ']';

return [{
  json: {
    query: `SELECT id, content, metadata, 1 - (embedding <=> '${embeddingStr}'::vector) AS similarity FROM knowledge_chunks WHERE store_id = '${store_id}' AND is_active = true AND 1 - (embedding <=> '${embeddingStr}'::vector) > ${threshold} ORDER BY embedding <=> '${embeddingStr}'::vector LIMIT ${topK};`,
    store_id,
    threshold
  }
}];

// ── Assemble full context for GPT ──
const validatedInput = $('Validate & Sanitize Input').item.json;
const storeProfile = $('Fetch Store Profile').item.json;
const aiConfig = $('Fetch AI Config').item.json;
const chunks = $('Vector Search — pgvector').all().map(i => i.json);

const agentName = aiConfig.agent_name || storeProfile.agent_name || 'Alex';
const brandVoice = aiConfig.brand_voice || storeProfile.brand_tone || 'friendly';
const fallback = aiConfig.fallback_message || 'reach out to the store directly for help';
const upsellEnabled = aiConfig.upsell_enabled || false;

// Build RAG context
let ragContext = '';
const chunkIds = [];
if (chunks && chunks.length > 0) {
  ragContext = chunks.map((c, i) => {
    chunkIds.push(c.id);
    return `[Source ${i + 1}]: ${c.content}`;
  }).join('\n\n');
} else {
  ragContext = '[NO RELEVANT CONTEXT FOUND — use fallback message]';
}

// Build conversation history text
const history = validatedInput.conversation_history || [];
let historyText = history.length > 0
  ? history.map(m => `${m.role === 'customer' ? 'Shopper' : 'AI'}: ${m.content}`).join('\n')
  : 'No previous messages.';

// Voice instructions per brand
const voiceInstructions = {
  friendly: 'Be warm, conversational, and approachable.',
  formal: 'Maintain a professional, courteous tone.',
  enthusiastic: 'Be energetic and positive. Express genuine excitement.',
  professional: 'Be clear, direct, and efficient.',
  casual: 'Be relaxed and easygoing.',
  luxury: 'Be refined and exclusive. Use elegant language.'
};

const systemPrompt = `You are ${agentName}, a helpful AI shopping assistant for ${storeProfile.store_name}.

Your role is to:
- Help shoppers find the right products for their needs
- Answer questions about products, shipping, returns, and store policies
- Suggest complementary items when genuinely relevant
- Guide shoppers through their shopping decisions

Your communication style is: ${brandVoice}
${voiceInstructions[brandVoice] || voiceInstructions.friendly}

CRITICAL RULES:
1. ONLY answer using the RETRIEVED CONTEXT below. Do NOT use general training knowledge for store-specific facts.
2. If the context does not contain the answer, say: "I don't have that information available, but you can ${fallback}."
3. Do NOT invent product prices, stock levels, or policy details.
4. Do NOT promise anything not explicitly stated in the context.
5. Keep responses concise — 3-5 sentences unless detail is clearly needed.
6. If the shopper's intent is unclear, ask one specific clarifying question.
${upsellEnabled ? '7. If related products exist in context, mention ONE naturally — never pushy.' : ''}

RETRIEVED CONTEXT:
${ragContext}

CONVERSATION HISTORY:
${historyText}`;

return [{
  json: {
    systemPrompt,
    userMessage: validatedInput.message,
    store_id: validatedInput.store_id,
    session_id: validatedInput.session_id,
    conversation_id: validatedInput.conversation_id,
    chunk_ids: chunkIds,
    rag_hit_count: chunks.length
  }
}];

// ── Parse GPT response and prepare output ──
const gptResponse = $('GPT-4o Mini — Generate Response').item.json;
const context = $('Assemble AI Context').item.json;

let aiMessage = '';
let tokensUsed = 0;

try {
  aiMessage = gptResponse.choices[0].message.content;
  tokensUsed = gptResponse.usage?.total_tokens || 0;
} catch (e) {
  aiMessage = 'Sorry, I had trouble generating a response. Please try again.';
}

// Create or get conversation ID
const conversationId = context.conversation_id || require('crypto').randomUUID();

return [{
  json: {
    message: aiMessage,
    conversation_id: conversationId,
    chunk_ids: context.chunk_ids,
    tokens_used: tokensUsed,
    store_id: context.store_id,
    session_id: context.session_id,
    user_message: context.userMessage,
    rag_hit_count: context.rag_hit_count
  }
}];

